import java.sql.*;

public class SQLInjectionFixed {
    public static void main(String[] args) {
        try {
            // Simulated user input (This should come from user input)
            String userInput = "'; DROP TABLE users; --";

            // Connect to the database
            Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password");

            // Create a PreparedStatement with parameterized query
            String query = "SELECT * FROM users WHERE username=?";
            PreparedStatement pstmt = conn.prepareStatement(query);

            // Set the parameter value using setString method
            pstmt.setString(1, userInput);

            // Execute the prepared statement
            ResultSet rs = pstmt.executeQuery();

            // Process the results (Not relevant for demonstrating the vulnerability)

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

